     3→namespace Illuminate\Database\Console\Migrations;
     4→
     5→use Illuminate\Console\Command;
     6→use Illuminate\Console\ConfirmableTrait;
     7→use Illuminate\Console\Prohibitable;
     8→use Illuminate\Contracts\Events\Dispatcher;
     9→use Illuminate\Database\Events\DatabaseRefreshed;
    10→use Illuminate\Database\Migrations\Migrator;
    11→use Symfony\Component\Console\Attribute\AsCommand;
    12→use Symfony\Component\Console\Input\InputOption;
    13→
    14→#[AsCommand(name: 'migrate:fresh')]
    15→class FreshCommand extends Command
    16→{
    17→    use ConfirmableTrait, Prohibitable;
    18→
    19→    /**
    20→     * The console command name.
    21→     *
    22→     * @var string
    23→     */
    24→    protected $name = 'migrate:fresh';
    25→
    26→    /**
    27→     * The console command description.
    28→     *
    29→     * @var string
    30→     */
    31→    protected $description = 'Drop all tables and re-run all migrations';
    32→
    33→    /**
    34→     * The migrator instance.
    35→     *
    36→     * @var \Illuminate\Database\Migrations\Migrator
    37→     */
    38→    protected $migrator;
    39→
    40→    /**
    41→     * Create a new fresh command instance.
    42→     *
    43→     * @param  \Illuminate\Database\Migrations\Migrator  $migrator
    44→     */
    45→    public function __construct(Migrator $migrator)
    46→    {
    47→        parent::__construct();
    48→
    49→        $this->migrator = $migrator;
    50→    }
    51→
    52→    /**
    53→     * Execute the console command.
    54→     *
    55→     * @return int
    56→     */
    57→    public function handle()
    58→    {
    59→        if ($this->isProhibited() ||
    60→            ! $this->confirmToProceed()) {
    61→            return Command::FAILURE;
    62→        }
    63→
    64→        $database = $this->input->getOption('database');
    65→
    66→        $this->migrator->usingConnection($database, function () use ($database) {
    67→            if ($this->migrator->repositoryExists()) {
    68→                $this->newLine();
    69→
    70→                $this->components->task('Dropping all tables', fn () => $this->callSilent('db:wipe', array_filter([
    71→                    '--database' => $database,
    72→                    '--drop-views' => $this->option('drop-views'),
    73→                    '--drop-types' => $this->option('drop-types'),
    74→                    '--force' => true,
    75→                ])) == 0);
    76→            }
    77→        });
    78→
    79→        $this->newLine();
    80→
    81→        $this->call('migrate', array_filter([
    82→            '--database' => $database,
    83→            '--path' => $this->input->getOption('path'),
    84→            '--realpath' => $this->input->getOption('realpath'),
    85→            '--schema-path' => $this->input->getOption('schema-path'),
    86→            '--force' => true,
    87→            '--step' => $this->option('step'),
    88→        ]));
    89→
    90→        if ($this->laravel->bound(Dispatcher::class)) {
    91→            $this->laravel[Dispatcher::class]->dispatch(
    92→                new DatabaseRefreshed($database, $this->needsSeeding())
    93→            );
    94→        }
    95→
    96→        if ($this->needsSeeding()) {
    97→            $this->runSeeder($database);
    98→        }
    99→
   100→        return 0;
   101→    }
   102→
   103→    /**
   104→     * Determine if the developer has requested database seeding.
   105→     *
   106→     * @return bool
   107→     */
   108→    protected function needsSeeding()
   109→    {
   110→        return $this->option('seed') || $this->option('seeder');
   111→    }
   112→
   113→    /**
   114→     * Run the database seeder command.
   115→     *
   116→     * @param  string  $database
   117→     * @return void
   118→     */
   119→    protected function runSeeder($database)
   120→    {
   121→        $this->call('db:seed', array_filter([
   122→            '--database' => $database,
   123→            '--class' => $this->option('seeder') ?: 'Database\\Seeders\\DatabaseSeeder',
   124→            '--force' => true,
   125→        ]));
   126→    }
   127→
   128→    /**
   129→     * Get the console command options.
   130→     *
   131→     * @return array
   132→     */
   133→    protected function getOptions()
   134→    {
   135→        return [
   136→            ['database', null, InputOption::VALUE_OPTIONAL, 'The database connection to use'],
   137→            ['drop-views', null, InputOption::VALUE_NONE, 'Drop all tables and views'],
   138→            ['drop-types', null, InputOption::VALUE_NONE, 'Drop all tables and types (Postgres only)'],
   139→            ['force', null, InputOption::VALUE_NONE, 'Force the operation to run when in production'],
   140→            ['path', null, InputOption::VALUE_OPTIONAL | InputOption::VALUE_IS_ARRAY, 'The path(s) to the migrations files to be executed'],
   141→            ['realpath', null, InputOption::VALUE_NONE, 'Indicate any provided migration file paths are pre-resolved absolute paths'],
   142→            ['schema-path', null, InputOption::VALUE_OPTIONAL, 'The path to a schema dump file'],
   143→            ['seed', null, InputOption::VALUE_NONE, 'Indicates if the seed task should be re-run'],
   144→            ['seeder', null, InputOption::VALUE_OPTIONAL, 'The class name of the root seeder'],
   145→            ['step', null, InputOption::VALUE_NONE, 'Force the migrations to be run so they can be rolled back individually'],
   146→        ];
   147→    }
   148→}
